import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';
import moment from 'moment';
import toast from 'react-hot-toast';

export default function VideoPlayer() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [video, setVideo] = useState(null);
    const [comments, setComments] = useState([]);
    const [newComment, setNewComment] = useState('');
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchVideo();
        fetchComments();
    }, [id]);

    const fetchVideo = async () => {
        try {
            const response = await axios.get(`/videos/${id}/`);
            setVideo(response.data);
        } catch (error) {
            console.error('Error fetching video:', error);
            toast.error('Видео не найдено');
            navigate('/');
        } finally {
            setLoading(false);
        }
    };

    const fetchComments = async () => {
        try {
            const response = await axios.get(`/videos/${id}/comments/`);
            setComments(response.data);
        } catch (error) {
            console.error('Error fetching comments:', error);
            setComments([]);
        }
    };

    const handleComment = async (e) => {
        e.preventDefault();

        if (!user) {
            toast.error('Войдите чтобы оставить комментарий');
            return;
        }

        if (!newComment.trim()) {
            toast.error('Напишите комментарий');
            return;
        }

        try {
            const response = await axios.post(`/videos/${id}/add_comment/`, {
                text: newComment
            });

            if (response.data) {
                setNewComment('');
                fetchComments();
                toast.success('Комментарий добавлен!');
            }
        } catch (error) {
            console.error('Error adding comment:', error);
            toast.error('Ошибка: ' + (error.response?.data?.error || 'Не удалось добавить комментарий'));
        }
    };

    const handleLike = async () => {
        if (!user) {
            toast.error('Войдите чтобы поставить лайк');
            return;
        }
        try {
            await axios.post(`/videos/${id}/like/`);
            fetchVideo();
            toast.success('Лайк поставлен!');
        } catch (error) {
            console.error('Error liking video:', error);
            toast.error('Ошибка');
        }
    };

    if (loading) {
        return <div className="flex justify-center items-center h-screen text-white">Загрузка...</div>;
    }

    if (!video) {
        return <div className="flex justify-center items-center h-screen text-white">Видео не найдено</div>;
    }

    return (
        <div className="pt-16 bg-black min-h-screen">
            <div className="container mx-auto px-4 py-8">
                <div className="flex flex-col lg:flex-row gap-8">
                    <div className="lg:w-3/4">
                        {/* Видео плеер */}
                        <div className="bg-black rounded-xl overflow-hidden">
                            <video
                                controls
                                autoPlay
                                className="w-full"
                                style={{ maxHeight: '70vh' }}
                                src={video.video_file}
                            >
                                Ваш браузер не поддерживает видео
                            </video>
                        </div>

                        {/* Информация о видео */}
                        <div className="mt-6">
                            <h1 className="text-2xl font-bold text-white">{video.title}</h1>
                            <div className="flex items-center justify-between mt-4 pb-4 border-b border-gray-800">
                                <div className="flex items-center space-x-4">
                                    <div className="flex items-center space-x-3">
                                        <div className="w-12 h-12 bg-purple-600 rounded-full flex items-center justify-center">
                                            <span className="text-white font-bold text-lg">
                                                {video.author?.username?.[0]?.toUpperCase()}
                                            </span>
                                        </div>
                                        <div>
                                            <p className="font-semibold text-white">{video.author?.username}</p>
                                            <p className="text-sm text-gray-400">{video.author?.subscriber_count} подписчиков</p>
                                        </div>
                                    </div>
                                </div>

                                <button
                                    onClick={handleLike}
                                    className="flex items-center space-x-2 px-6 py-2 bg-red-600 rounded-full hover:bg-red-700 transition"
                                >
                                    ❤️
                                    <span>{video.like_count || 0}</span>
                                </button>
                            </div>

                            <div className="mt-4 p-4 bg-gray-900 rounded-xl">
                                <p className="text-gray-300">{video.description || 'Нет описания'}</p>
                                <p className="text-sm text-gray-500 mt-2">{video.views} просмотров</p>
                            </div>

                            {/* Комментарии */}
                            <div className="mt-8">
                                <h3 className="text-xl font-bold text-white mb-4">
                                    💬 Комментарии ({comments.length})
                                </h3>

                                {/* Форма добавления комментария */}
                                <form onSubmit={handleComment} className="mb-6">
                                    <div className="flex space-x-3">
                                        <div className="flex-1">
                                            <textarea
                                                value={newComment}
                                                onChange={(e) => setNewComment(e.target.value)}
                                                placeholder={user ? "Напишите комментарий..." : "Войдите чтобы оставить комментарий"}
                                                disabled={!user}
                                                rows="3"
                                                className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-purple-500 disabled:opacity-50"
                                            />
                                        </div>
                                    </div>
                                    {user && (
                                        <div className="mt-2 text-right">
                                            <button
                                                type="submit"
                                                className="px-6 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition font-semibold"
                                            >
                                                Отправить
                                            </button>
                                        </div>
                                    )}
                                </form>

                                {/* Список комментариев */}
                                <div className="space-y-4">
                                    {comments.length === 0 ? (
                                        <div className="text-center text-gray-500 py-8 bg-gray-900 rounded-lg">
                                            <p>Нет комментариев. Будьте первым! 💬</p>
                                        </div>
                                    ) : (
                                        comments.map(comment => (
                                            <div key={comment.id} className="p-4 bg-gray-900 rounded-lg">
                                                <div className="flex items-start space-x-3">
                                                    <div className="w-8 h-8 bg-gray-700 rounded-full flex items-center justify-center flex-shrink-0">
                                                        <span className="text-white text-sm">
                                                            {comment.user?.username?.[0]?.toUpperCase()}
                                                        </span>
                                                    </div>
                                                    <div className="flex-1">
                                                        <div className="flex items-center space-x-2 mb-1">
                                                            <span className="font-semibold text-purple-400">
                                                                {comment.user?.username}
                                                            </span>
                                                            <span className="text-gray-500 text-xs">
                                                                {moment(comment.created_at).fromNow()}
                                                            </span>
                                                        </div>
                                                        <p className="text-gray-300">{comment.text}</p>
                                                    </div>
                                                </div>
                                            </div>
                                        ))
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Рекомендации */}
                    <div className="lg:w-1/4">
                        <h3 className="text-xl font-bold text-white mb-4">🎬 Рекомендации</h3>
                        <div className="space-y-4">
                            <div className="text-center text-gray-500 py-8 bg-gray-900 rounded-lg">
                                <p>Скоро здесь будут рекомендации</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
